"""
Parameterized generator for GH616_next.js_91744.

Source PR:    https://github.com/vercel/next.js/pull/91744
Source Issue: N/A

Seed varies: renames 'about' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH616_next.js_91744'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH616_next.js_91744'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('about', 'about' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH616_next.js_91744',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'vercel/next.js',
                "pr_number": 91744,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/vercel/next.js/pull/91744",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'docs/01-app/01-getting-started/10-error-handling.mdx': '---\ntitle: Error Handling\ndescription: Learn how to display expected errors and handle uncaught exceptions.\nrelated:\n  title: API Reference\n  description: Learn more about the features mentioned in this page by reading the API Reference.\n  links:\n    - app/api-reference/functions/redirect\n    - app/api-reference/file-conventions/error\n    - app/api-reference/functions/catchError\n    - app/api-reference/functions/not-found\n    - app/api-reference/file-conventions/not-found\n---\n\nErrors can be divided into two categories: [expected errors](#handling-expected-errors) and [uncaught exceptions](#handling-uncaught-exceptions). This page will walk you through how you can handle these errors in your Next.js application.\n\n## Handling expected errors\n\nExpected errors are those that can occur during the normal operation of the application, such as those from [server-side form validation](/docs/app/guides/forms) or failed requests. These errors should be handled explicitly and returned to the client.\n\n### Server Functions\n\nYou can use the [`useActionState`](https://react.dev/reference/react/useActionState) hook to handle expected errors in [Server Functions](https://react.dev/reference/rsc/server-functions).\n\nFor these errors, avoid using `try`/`catch` blocks and throw errors. Instead, model expected errors as return values.\n\n```ts filename="app/actions.ts" switcher\n\'use server\'\n\nexport async function createPost(prevState: any, formData: FormData) {\n  const title = formData.get(\'title\')\n  const content = formData.get(\'content\')\n\n  const res = await fetch(\'https://api.vercel.app/posts\', {\n    method: \'POST\',\n    body: { title, content },\n  })\n  const json = await res.json()\n\n  if (!res.ok) {\n    return { message: \'Failed to create post\' }\n  }\n}\n```\n\n```js filename="app/actions.js" switcher\n\'use server\'\n\nexport async function createPost(prevState, formData) {\n  const title = formData.get(\'title\')\n  const content = formData.get(\'content\')\n\n  const res = await fetch(\'https://api.vercel.app/posts\', {\n    method: \'POST\',\n    body: { title, content },\n  })\n  const json = await res.json()\n\n  if (!res.ok) {\n    return { message: \'Failed to create post\' }\n  }\n}\n```\n\nYou can pass your action to the `useActionState` hook and use the returned `state` to display an error message.\n\n```tsx filename="app/ui/form.tsx" highlight={11,19} switcher\n\'use client\'\n\nimport { useActionState } from \'react\'\nimport { createPost } from \'@/app/actions\'\n\nconst initialState = {\n  message: \'\',\n}\n\nexport function Form() {\n  const [state, formAction, pending] = useActionState(createPost, initialState)\n\n  return (\n    <form action={formAction}>\n      <label htmlFor="title">Title</label>\n      <input type="text" id="title" name="title" required />\n      <label htmlFor="content">Content</label>\n      <textarea id="content" name="content" required />\n      {state?.message && <p aria-live="polite">{state.message}</p>}\n      <button disabled={pending}>Create Post</button>\n    </form>\n  )\n}\n```\n\n```jsx filename="app/ui/form.js" highlight={11,19} switcher\n\'use client\'\n\nimport { useActionState } from \'react\'\nimport { createPost } from \'@/app/actions\'\n\nconst initialState = {\n  message: \'\',\n}\n\nexport function Form() {\n  const [state, formAction, pending] = useActionState(createPost, initialState)\n\n  return (\n    <form action={formAction}>\n      <label htmlFor="title">Title</label>\n      <input type="text" id="title" name="title" required />\n      <label htmlFor="content">Content</label>\n      <textarea id="content" name="content" required />\n      {state?.message && <p aria-live="polite">{state.message}</p>}\n      <button disabled={pending}>Create Post</button>\n    </form>\n  )\n}\n```\n\n### Server Components\n\nWhen fetching data inside of a Server Component, you can use the response to conditionally render an error message or [`redirect`](/docs/app/api-reference/functions/redirect).\n\n```tsx filename="app/page.tsx" switcher\nexport default async function Page() {\n  const res = await fetch(`https://...`)\n  const data = await res.json()\n\n  if (!res.ok) {\n    return \'There was an error.\'\n  }\n\n  return \'...\'\n}\n```\n\n```jsx filename="app/page.js" switcher\nexport default async function Page() {\n  const res = await fetch(`https://...`)\n  const data = await res.json()\n\n  if (!res.ok) {\n    return \'There was an error.\'\n  }\n\n  return \'...\'\n}\n```\n\n### Not found\n\nYou can call the [`notFound`](/docs/app/api-reference/functions/not-found) function within a route segment and use the [`not-found.js`](/docs/app/api-reference/file-conventions/not-found) file to show a 404 UI.\n\n```tsx filename="app/blog/[slug]/page.tsx" switcher\nimport { notFound } from \'next/navigation\'\nimport { getPostBySlug } from \'@/lib/posts\'\n\nexport default async function Page({\n  params,\n}: {\n  params: Promise<{ slug: string }>\n}) {\n  const { slug } = await params\n  const post = getPostBySlug(slug)\n\n  if (!post) {\n    notFound()\n  }\n\n  return <div>{post.title}</div>\n}\n```\n\n```jsx filename="app/blog/[slug]/page.js" switcher\nimport { notFound } from \'next/navigation\'\nimport { getPostBySlug } from \'@/lib/posts\'\n\nexport default async function Page({ params }) {\n  const { slug } = await params\n  const post = getPostBySlug(slug)\n\n  if (!post) {\n    notFound()\n  }\n\n  return <div>{post.title}</div>\n}\n```\n\n```tsx filename="app/blog/[slug]/not-found.tsx" switcher\nexport default function NotFound() {\n  return <div>404 - Page Not Found</div>\n}\n```\n\n```jsx filename="app/blog/[slug]/not-found.js" switcher\nexport default function NotFound() {\n  return <div>404 - Page Not Found</div>\n}\n```\n\n## Handling uncaught exceptions\n\nUncaught exceptions are unexpected errors that indicate bugs or issues that should not occur during the normal flow of your application. These should be handled by throwing errors, which will then be caught by error boundaries.\n\n### Nested error boundaries\n\nNext.js uses error boundaries to handle uncaught exceptions. Error boundaries catch errors in their child components and display a fallback UI instead of the component tree that crashed.\n\nCreate an error boundary by adding an [`error.js`](/docs/app/api-reference/file-conventions/error) file inside a route segment and exporting a React component:\n\n```tsx filename="app/dashboard/error.tsx" switcher\n\'use client\' // Error boundaries must be Client Components\n\nimport { useEffect } from \'react\'\n\nexport default function ErrorPage({\n  error,\n  unstable_retry,\n}: {\n  error: Error & { digest?: string }\n  unstable_retry: () => void\n}) {\n  useEffect(() => {\n    // Log the error to an error reporting service\n    console.error(error)\n  }, [error])\n\n  return (\n    <div>\n      <h2>Something went wrong!</h2>\n      <button\n        onClick={\n          // Attempt to recover by re-fetching and re-rendering the segment\n          () => unstable_retry()\n        }\n      >\n        Try again\n      </button>\n    </div>\n  )\n}\n```\n\n```jsx filename="app/dashboard/error.js" switcher\n\'use client\' // Error boundaries must be Client Components\n\nimport { useEffect } from \'react\'\n\nexport default function ErrorPage({ error, unstable_retry }) {\n  useEffect(() => {\n    // Log the error to an error reporting service\n    console.error(error)\n  }, [error])\n\n  return (\n    <div>\n      <h2>Something went wrong!</h2>\n      <button\n        onClick={\n          // Attempt to recover by re-fetching and re-rendering the segment\n          () => unstable_retry()\n        }\n      >\n        Try again\n      </button>\n    </div>\n  )\n}\n```\n\nErrors will bubble up to the nearest parent error boundary. This allows for granular error handling by placing `error.tsx` files at different levels in the [route hierarchy](/docs/app/getting-started/project-structure#component-hierarchy).\n\n<Image\n  alt="Nested Error Component Hierarchy"\n  srcLight="/docs/light/nested-error-component-hierarchy.png"\n  srcDark="/docs/dark/nested-error-component-hierarchy.png"\n  width="1600"\n  height="687"\n/>\n\nFor component-level error recovery, the [`unstable_catchError`](/docs/app/api-reference/functions/catchError) function lets you create error boundaries that can wrap any part of your component tree:\n\n```tsx filename="app/custom-error-boundary.tsx" switcher\n\'use client\'\n\nimport { unstable_catchError as catchError, type ErrorInfo } from \'next/error\'\n\nfunction ErrorFallback(\n  props: { title: string },\n  { error, unstable_retry: retry }: ErrorInfo\n) {\n  return (\n    <div>\n      <h2>{props.title}</h2>\n      <p>{error.message}</p>\n      <button onClick={() => retry()}>Try again</button>\n    </div>\n  )\n}\n\nexport default catchError(ErrorFallback)\n```\n\n```jsx filename="app/custom-error-boundary.js" switcher\n\'use client\'\n\nimport { unstable_catchError as catchError } from \'next/error\'\n\nfunction ErrorFallback(props, { error, unstable_retry: retry }) {\n  return (\n    <div>\n      <h2>{props.title}</h2>\n      <p>{error.message}</p>\n      <button onClick={() => retry()}>Try again</button>\n    </div>\n  )\n}\n\nexport default catchError(ErrorFallback)\n```\n\nThen use the returned component as a wrapper in any layout or page:\n\n```tsx filename="app/some-component.tsx" switcher\nimport ErrorBoundary from \'./custom-error-boundary\'\n\nexport default function Component({ children }: { children: React.ReactNode }) {\n  return <ErrorBoundary title="Dashboard Error">{children}</ErrorBoundary>\n}\n```\n\n```jsx filename="app/some-component.js" switcher\nimport ErrorBoundary from \'./custom-error-boundary\'\n\nexport default function Component({ children }) {\n  return <ErrorBoundary title="Dashboard Error">{children}</ErrorBoundary>\n}\n```\n\nError boundaries don\'t catch errors inside event handlers. They\'re designed to catch errors [during rendering](https://react.dev/reference/react/Component#static-getderivedstatefromerror) to show a **fallback UI** instead of crashing the whole app.\n\nIn general, errors in event handlers or async code aren’t handled by error boundaries because they run after rendering.\n\nTo handle these cases, catch the error manually and store it using `useState` or `useReducer`, then update the UI to inform the user.\n\n```tsx\n\'use client\'\n\nimport { useState } from \'react\'\n\nexport function Button() {\n  const [error, setError] = useState(null)\n\n  const handleClick = () => {\n    try {\n      // do some work that might fail\n      throw new Error(\'Exception\')\n    } catch (reason) {\n      setError(reason)\n    }\n  }\n\n  if (error) {\n    /* render fallback UI */\n  }\n\n  return (\n    <button type="button" onClick={handleClick}>\n      Click me\n    </button>\n  )\n}\n```\n\nNote that unhandled errors inside `startTransition` from `useTransition`, will bubble up to the nearest error boundary.\n\n```tsx\n\'use client\'\n\nimport { useTransition } from \'react\'\n\nexport function Button() {\n  const [pending, startTransition] = useTransition()\n\n  const handleClick = () =>\n    startTransition(() => {\n      throw new Error(\'Exception\')\n    })\n\n  return (\n    <button type="button" onClick={handleClick}>\n      Click me\n    </button>\n  )\n}\n```\n\n### Global errors\n\nWhile less common, you can handle errors in the root layout using the [`global-error.js`](/docs/app/api-reference/file-conventions/error#global-error) file, located in the root app directory, even when leveraging [internationalization](/docs/app/guides/internationalization). Global error UI must define its own `<html>` and `<body>` tags, since it is replacing the root layout or template when active.\n\n```tsx filename="app/global-error.tsx" switcher\n\'use client\' // Error boundaries must be Client Components\n\nexport default function GlobalError({\n  error,\n  unstable_retry,\n}: {\n  error: Error & { digest?: string }\n  unstable_retry: () => void\n}) {\n  return (\n    // global-error must include html and body tags\n    <html>\n      <body>\n        <h2>Something went wrong!</h2>\n        <button onClick={() => unstable_retry()}>Try again</button>\n      </body>\n    </html>\n  )\n}\n```\n\n```jsx filename="app/global-error.js" switcher\n\'use client\' // Error boundaries must be Client Components\n\nexport default function GlobalError({ error, unstable_retry }) {\n  return (\n    // global-error must include html and body tags\n    <html>\n      <body>\n        <h2>Something went wrong!</h2>\n        <button onClick={() => unstable_retry()}>Try again</button>\n      </body>\n    </html>\n  )\n}\n```\n',
            'docs/01-app/03-api-reference/03-file-conventions/error.mdx': '---\ntitle: error.js\ndescription: API reference for the error.js special file.\nrelated:\n  title: Learn more about error handling\n  links:\n    - app/getting-started/error-handling\n---\n\nAn **error** file allows you to handle unexpected runtime errors and display fallback UI.\n\n<Image\n  alt="error.js special file"\n  srcLight="/docs/light/error-special-file.png"\n  srcDark="/docs/dark/error-special-file.png"\n  width="1600"\n  height="606"\n/>\n\n```tsx filename="app/dashboard/error.tsx" switcher\n\'use client\' // Error boundaries must be Client Components\n\nimport { useEffect } from \'react\'\n\nexport default function Error({\n  error,\n  unstable_retry,\n}: {\n  error: Error & { digest?: string }\n  unstable_retry: () => void\n}) {\n  useEffect(() => {\n    // Log the error to an error reporting service\n    console.error(error)\n  }, [error])\n\n  return (\n    <div>\n      <h2>Something went wrong!</h2>\n      <button\n        onClick={\n          // Attempt to recover by re-fetching and re-rendering the segment\n          () => unstable_retry()\n        }\n      >\n        Try again\n      </button>\n    </div>\n  )\n}\n```\n\n```jsx filename="app/dashboard/error.js" switcher\n\'use client\' // Error boundaries must be Client Components\n\nimport { useEffect } from \'react\'\n\nexport default function Error({ error, unstable_retry }) {\n  useEffect(() => {\n    // Log the error to an error reporting service\n    console.error(error)\n  }, [error])\n\n  return (\n    <div>\n      <h2>Something went wrong!</h2>\n      <button\n        onClick={\n          // Attempt to recover by re-fetching and re-rendering the segment\n          () => unstable_retry()\n        }\n      >\n        Try again\n      </button>\n    </div>\n  )\n}\n```\n\n`error.js` wraps a route segment and its nested children in a [React Error Boundary](https://react.dev/reference/react/Component#catching-rendering-errors-with-an-error-boundary). When an error throws within the boundary, the `error` component shows as the fallback UI.\n\n<Image\n  alt="How error.js works"\n  srcLight="/docs/light/error-overview.png"\n  srcDark="/docs/dark/error-overview.png"\n  width="1600"\n  height="903"\n/>\n\n> **Good to know**:\n>\n> - The [React DevTools](https://react.dev/learn/react-developer-tools) allow you to toggle error boundaries to test error states.\n> - If you want errors to bubble up to the parent error boundary, you can `throw` when rendering the `error` component.\n> - For component-level error recovery that aren\'t tied to route segments like [`error.js`](/docs/app/api-reference/file-conventions/error), use the [`unstable_catchError`](/docs/app/api-reference/functions/catchError) function.\n\nIn the [component hierarchy](/docs/app/getting-started/project-structure#component-hierarchy), `error.js` wraps `loading.js`, `not-found.js`, `page.js`, and nested `layout.js` files in a React error boundary. It does **not** wrap the `layout.js` or `template.js` above it in the same segment. To handle errors in the root layout, use [`global-error.js`](/docs/app/api-reference/file-conventions/error#global-error).\n\n## Reference\n\n### Props\n\n#### `error`\n\nAn instance of an [`Error`](https://developer.mozilla.org/docs/Web/JavaScript/Reference/Global_Objects/Error) object forwarded to the `error.js` Client Component.\n\n> **Good to know:** During development, the `Error` object forwarded to the client will be serialized and include the `message` of the original error for easier debugging. However, **this behavior is different in production** to avoid leaking potentially sensitive details included in the error to the client.\n\n#### `error.message`\n\n- Errors forwarded from Client Components show the original `Error` message.\n- Errors forwarded from Server Components show a generic message with an identifier. This is to prevent leaking sensitive details. You can use the identifier, under `errors.digest`, to match the corresponding server-side logs.\n\n#### `error.digest`\n\nAn automatically generated hash of the error thrown. It can be used to match the corresponding error in server-side logs.\n\n#### `unstable_retry`\n\nThe cause of an error can sometimes be temporary. In these cases, trying again might resolve the issue.\n\nAn error component can use the `unstable_retry()` function to prompt the user to attempt to recover from the error. When executed, the function will try to re-fetch and re-render the error boundary\'s contents. If successful, the fallback error component is replaced with the result of the re-render.\n\n```tsx filename="app/dashboard/error.tsx" switcher\n\'use client\' // Error boundaries must be Client Components\n\nexport default function Error({\n  error,\n  unstable_retry,\n}: {\n  error: Error & { digest?: string }\n  unstable_retry: () => void\n}) {\n  return (\n    <div>\n      <h2>Something went wrong!</h2>\n      <button onClick={() => unstable_retry()}>Try again</button>\n    </div>\n  )\n}\n```\n\n```jsx filename="app/dashboard/error.js" switcher\n\'use client\' // Error boundaries must be Client Components\n\nexport default function Error({ error, unstable_retry }) {\n  return (\n    <div>\n      <h2>Something went wrong!</h2>\n      <button onClick={() => unstable_retry()}>Try again</button>\n    </div>\n  )\n}\n```\n\n#### `reset`\n\nIn most cases, you should use [`unstable_retry()`](#unstable_retry) instead. However, if you have a specific reason to clear the error state and re-render the error boundary\'s contents without re-fetching the contents, you can use the `reset()` function.\n\n## Examples\n\n### Global Error\n\nWhile less common, you can handle errors in the root layout or template using `global-error.jsx`, located in the root app directory, even when leveraging [internationalization](/docs/app/guides/internationalization). Global error UI must define its own `<html>` and `<body>` tags, global styles, fonts, or other dependencies that your error page requires. This file replaces the root layout or template when active.\n\n> **Good to know**: Error boundaries must be [Client Components](/docs/app/getting-started/server-and-client-components#using-client-components), which means that [`metadata` and `generateMetadata`](/docs/app/getting-started/metadata-and-og-images) exports are not supported in `global-error.jsx`. As an alternative, you can use the React [`<title>`](https://react.dev/reference/react-dom/components/title) component.\n\n```tsx filename="app/global-error.tsx" switcher\n\'use client\' // Error boundaries must be Client Components\n\nexport default function GlobalError({\n  error,\n  unstable_retry,\n}: {\n  error: Error & { digest?: string }\n  unstable_retry: () => void\n}) {\n  return (\n    // global-error must include html and body tags\n    <html>\n      <body>\n        <h2>Something went wrong!</h2>\n        <button onClick={() => unstable_retry()}>Try again</button>\n      </body>\n    </html>\n  )\n}\n```\n\n```jsx filename="app/global-error.js" switcher\n\'use client\' // Error boundaries must be Client Components\n\nexport default function GlobalError({ error, unstable_retry }) {\n  return (\n    // global-error must include html and body tags\n    <html>\n      <body>\n        <h2>Something went wrong!</h2>\n        <button onClick={() => unstable_retry()}>Try again</button>\n      </body>\n    </html>\n  )\n}\n```\n\n### Graceful error recovery with a custom error boundary\n\nWhen rendering fails on the client, it can be useful to show the last known server rendered UI for a better user experience.\n\nThe `GracefullyDegradingErrorBoundary` is an example of a custom error boundary that captures and preserves the current HTML before an error occurs. If a rendering error happens, it re-renders the captured HTML and displays a persistent notification bar to inform the user.\n\n```tsx filename="app/dashboard/error.tsx" switcher\n\'use client\'\n\nimport React, { Component, ErrorInfo, ReactNode } from \'react\'\n\ninterface ErrorBoundaryProps {\n  children: ReactNode\n  onError?: (error: Error, errorInfo: ErrorInfo) => void\n}\n\ninterface ErrorBoundaryState {\n  hasError: boolean\n}\n\nexport class GracefullyDegradingErrorBoundary extends Component<\n  ErrorBoundaryProps,\n  ErrorBoundaryState\n> {\n  private contentRef: React.RefObject<HTMLDivElement | null>\n\n  constructor(props: ErrorBoundaryProps) {\n    super(props)\n    this.state = { hasError: false }\n    this.contentRef = React.createRef()\n  }\n\n  static getDerivedStateFromError(_: Error): ErrorBoundaryState {\n    return { hasError: true }\n  }\n\n  componentDidCatch(error: Error, errorInfo: ErrorInfo) {\n    if (this.props.onError) {\n      this.props.onError(error, errorInfo)\n    }\n  }\n\n  render() {\n    if (this.state.hasError) {\n      // Render the current HTML content without hydration\n      return (\n        <>\n          <div\n            ref={this.contentRef}\n            suppressHydrationWarning\n            dangerouslySetInnerHTML={{\n              __html: this.contentRef.current?.innerHTML || \'\',\n            }}\n          />\n          <div className="fixed bottom-0 left-0 right-0 bg-red-600 text-white py-4 px-6 text-center">\n            <p className="font-semibold">\n              An error occurred during page rendering\n            </p>\n          </div>\n        </>\n      )\n    }\n\n    return <div ref={this.contentRef}>{this.props.children}</div>\n  }\n}\n\nexport default GracefullyDegradingErrorBoundary\n```\n\n```jsx filename="app/dashboard/error.js" switcher\n\'use client\'\n\nimport React, { Component, createRef } from \'react\'\n\nclass GracefullyDegradingErrorBoundary extends Component {\n  constructor(props) {\n    super(props)\n    this.state = { hasError: false }\n    this.contentRef = createRef()\n  }\n\n  static getDerivedStateFromError(_) {\n    return { hasError: true }\n  }\n\n  componentDidCatch(error, errorInfo) {\n    if (this.props.onError) {\n      this.props.onError(error, errorInfo)\n    }\n  }\n\n  render() {\n    if (this.state.hasError) {\n      // Render the current HTML content without hydration\n      return (\n        <>\n          <div\n            ref={this.contentRef}\n            suppressHydrationWarning\n            dangerouslySetInnerHTML={{\n              __html: this.contentRef.current?.innerHTML || \'\',\n            }}\n          />\n          <div className="fixed bottom-0 left-0 right-0 bg-red-600 text-white py-4 px-6 text-center">\n            <p className="font-semibold">\n              An error occurred during page rendering\n            </p>\n          </div>\n        </>\n      )\n    }\n\n    return <div ref={this.contentRef}>{this.props.children}</div>\n  }\n}\n\nexport default GracefullyDegradingErrorBoundary\n```\n\n## Version History\n\n| Version   | Changes                                     |\n| --------- | ------------------------------------------- |\n| `v16.2.0` | `unstable_retry` prop added.                |\n| `v15.2.0` | Also display `global-error` in development. |\n| `v13.1.0` | `global-error` introduced.                  |\n| `v13.0.0` | `error` introduced.                         |\n',
            'docs/01-app/03-api-reference/04-functions/catchError.mdx': '---\ntitle: unstable_catchError\ndescription: API Reference for the unstable_catchError function.\nrelated:\n  title: Learn more about error handling\n  links:\n    - app/getting-started/error-handling\n    - app/api-reference/file-conventions/error\n---\n\nThe `unstable_catchError` function creates a component that wraps its children in an error boundary. It provides a programmatic alternative to the [`error.js`](/docs/app/api-reference/file-conventions/error) file convention, enabling component-level error recovery anywhere in your component tree.\n\n`unstable_catchError` can be called from [Client Components](/docs/app/getting-started/server-and-client-components).\n\n```tsx filename="app/custom-error-boundary.tsx" switcher\n\'use client\'\n\nimport { unstable_catchError } from \'next/error\'\n\nfunction ErrorFallback(\n  props: { title: string },\n  { error, unstable_retry: retry }: { error: Error; unstable_retry: () => void }\n) {\n  return (\n    <div>\n      <h2>{props.title}</h2>\n      <p>{error.message}</p>\n      <button onClick={() => retry()}>Try again</button>\n    </div>\n  )\n}\n\nexport default unstable_catchError(ErrorFallback)\n```\n\n```jsx filename="app/custom-error-boundary.js" switcher\n\'use client\'\n\nimport { unstable_catchError } from \'next/error\'\n\nfunction ErrorFallback(props, { error, unstable_retry: retry }) {\n  return (\n    <div>\n      <h2>{props.title}</h2>\n      <p>{error.message}</p>\n      <button onClick={() => retry()}>Try again</button>\n    </div>\n  )\n}\n\nexport default unstable_catchError(ErrorFallback)\n```\n\n## Reference\n\n### Parameters\n\n`unstable_catchError` accepts a single argument:\n\n```ts\nconst ErrorWrapper = unstable_catchError(fallback)\n```\n\n#### `fallback`\n\nA function that renders the error UI when an error is caught. It receives two arguments:\n\n- `props` — The props passed to the wrapper component (excluding `children`).\n- `errorInfo` — An object containing information about the error:\n\n| Property         | Type                                                                                        | Description                                                                                                                                              |\n| ---------------- | ------------------------------------------------------------------------------------------- | -------------------------------------------------------------------------------------------------------------------------------------------------------- |\n| `error`          | [`Error`](https://developer.mozilla.org/docs/Web/JavaScript/Reference/Global_Objects/Error) | The error instance that was caught.                                                                                                                      |\n| `unstable_retry` | `() => void`                                                                                | Re-fetches and re-renders the error boundary\'s contents. If successful, the fallback is replaced with the re-rendered result.                            |\n| `reset`          | `() => void`                                                                                | Resets the error state and re-renders without re-fetching. Use [`retry()`](/docs/app/api-reference/file-conventions/error#unstable_retry) in most cases. |\n\nThe `fallback` function must be a Client Component (or defined in a `\'use client\'` module).\n\n### Returns\n\n`unstable_catchError` returns a React component that:\n\n- Accepts the same props as your fallback\'s first argument, plus `children`.\n- Wraps `children` in an error boundary.\n- Renders the `fallback` when an error is caught in `children`.\n\n## Examples\n\n### Client Component\n\nDefine a fallback and use the returned component to wrap parts of your UI:\n\n```tsx filename="app/some-component.tsx" switcher\nimport ErrorWrapper from \'../custom-error-boundary\'\n\nexport default function Component({ children }: { children: React.ReactNode }) {\n  return <ErrorWrapper title="Dashboard Error">{children}</ErrorWrapper>\n}\n```\n\n```jsx filename="app/some-component.js" switcher\nimport ErrorWrapper from \'../custom-error-boundary\'\n\nexport default function Component({ children }) {\n  return <ErrorWrapper title="Dashboard Error">{children}</ErrorWrapper>\n}\n```\n\n### Recovering from errors\n\nUse `retry()` to prompt the user to recover from the error. When called, the function re-fetches and re-renders the error boundary\'s contents. If successful, the fallback is replaced with the re-rendered result.\n\nIn most cases, use `retry()` instead of `reset()`. The `reset()` function only clears the error state and re-renders without re-fetching, which means it won\'t recover from Server Component errors.\n\n```tsx filename="app/custom-error-boundary.tsx" highlight={16,17} switcher\n\'use client\'\n\nimport { unstable_catchError } from \'next/error\'\n\nfunction ErrorFallback(\n  props: {},\n  {\n    error,\n    unstable_retry: retry,\n    reset,\n  }: { error: Error; unstable_retry: () => void; reset: () => void }\n) {\n  return (\n    <div>\n      <p>{error.message}</p>\n      <button onClick={() => retry()}>Try again</button>\n      <button onClick={() => reset()}>Reset</button>\n    </div>\n  )\n}\n\nexport default unstable_catchError(ErrorFallback)\n```\n\n```jsx filename="app/custom-error-boundary.js" highlight={9,10} switcher\n\'use client\'\n\nimport { unstable_catchError } from \'next/error\'\n\nfunction ErrorFallback(props, { error, unstable_retry: retry, reset }) {\n  return (\n    <div>\n      <p>{error.message}</p>\n      <button onClick={() => retry()}>Try again</button>\n      <button onClick={() => reset()}>Reset</button>\n    </div>\n  )\n}\n\nexport default unstable_catchError(ErrorFallback)\n```\n\n### Server-rendered error fallback\n\nYou can pass server-rendered content as a prop to display data-driven fallback UI. This works by rendering a Server Component as a `React.ReactNode` prop that the fallback displays when an error is caught.\n\n> **Good to know**: This pattern eagerly renders the fallback on every page render, even when no error occurs. For most use cases, a simpler client-side fallback is sufficient.\n\n```tsx filename="app/error-boundary.tsx" switcher\n\'use client\'\n\nimport { unstable_catchError } from \'next/error\'\nimport type { ErrorInfo } from \'next/error\'\n\nfunction ErrorFallback(\n  props: { fallback: React.ReactNode },\n  errorInfo: ErrorInfo\n) {\n  return props.fallback\n}\n\nexport default unstable_catchError(ErrorFallback)\n```\n\n```jsx filename="app/error-boundary.js" switcher\n\'use client\'\n\nimport { unstable_catchError } from \'next/error\'\n\nfunction ErrorFallback(props, errorInfo) {\n  return props.fallback\n}\n\nexport default unstable_catchError(ErrorFallback)\n```\n\n```tsx filename="app/some-component.tsx" switcher\nimport ErrorBoundary from \'../error-boundary\'\n\nasync function ErrorFallback() {\n  const data = await getData()\n  return <div>{data.message}</div>\n}\n\nexport default function Component({ children }: { children: React.ReactNode }) {\n  return <ErrorBoundary fallback={<ErrorFallback />}>{children}</ErrorBoundary>\n}\n```\n\n```jsx filename="app/some-component.js" switcher\nimport ErrorBoundary from \'../error-boundary\'\n\nasync function ErrorFallback() {\n  const data = await getData()\n  return <div>{data.message}</div>\n}\n\nexport default function Component({ children }) {\n  return <ErrorBoundary fallback={<ErrorFallback />}>{children}</ErrorBoundary>\n}\n```\n\n> **Good to know**:\n>\n> - Unlike the `error.js` file convention which is scoped to route segments, `unstable_catchError` can be used to wrap any part of your component tree for component-level error recovery.\n> - Props passed to the wrapper component are forwarded to the fallback function, making it easy to create reusable error UIs with different configurations.\n> - You don\'t need to wrap `error.js` default exports with `unstable_catchError`. The [`error.js`](/docs/app/api-reference/file-conventions/error) file convention already renders inside a built-in error boundary provided by Next.js.\n\n## Version History\n\n| Version   | Changes                           |\n| --------- | --------------------------------- |\n| `v16.2.0` | `unstable_catchError` introduced. |\n',
        }
